export function getQiyunByCategory(类别: 气运类别): 气运数据[] {
    return 气运数据列表.filter(q => q.类别 === 类别);
}

export function getQiyunByRarity(稀有度: 气运稀有度): 气运数据[] {
    return 气运数据列表.filter(q => q.稀有度 === 稀有度);
}

export function getQiyunDetail(名称: string): 气运数据 | undefined {
    return 气运数据列表.find(q => q.名称 === 名称);
}

export type 气运能力类型 = '战斗' | '生存' | '社交' | '谋略' | '特殊' | '辅助';

export function getQiyunByType(能力类型: 气运能力类型): 气运数据[] {
    return 气运数据列表.filter(q => q.能力类型 === 能力类型);
}

export function getQiyunByRealm(境界层级: number): 气运数据[] {
    return 气运数据列表.filter(q => {
        const range = q.适用境界 || [0, 99];
        return 境界层级 >= range[0] && 境界层级 <= range[1];
    });
}

function applyQiyunFilters(pool: 气运数据[], options?: {
    类别?: 气运类别;
    稀有度?: 气运稀有度;
    excludeNsfw?: boolean;
    nsfwOnly?: boolean;
    成人内容开启?: boolean;
    能力类型?: 气运能力类型;
    适用境界Min?: number;
    适用境界Max?: number;
}): 气运数据[] {
    if (options?.类别) pool = pool.filter(q => q.类别 === options.类别);
    if (options?.稀有度) pool = pool.filter(q => q.稀有度 === options.稀有度);
    if (options?.excludeNsfw) pool = pool.filter(q => !q.nsfw等级);
    if (options?.nsfwOnly) pool = pool.filter(q => q.nsfw等级 && q.nsfw等级 > 0);
    if (options?.成人内容开启 === false) pool = pool.filter(q => !q.nsfw等级 || q.nsfw等级 < 2);
    if (options?.能力类型) pool = pool.filter(q => q.能力类型 === options.能力类型);
    if (options?.适用境界Min !== undefined || options?.适用境界Max !== undefined) {
        pool = pool.filter(q => {
            const range = q.适用境界 || [0, 99];
            const min = options?.适用境界Min ?? range[0];
            const max = options?.适用境界Max ?? range[1];
            return range[0] >= min && range[1] <= max;
        });
    }
    return pool;
}

export function randomQiyun(count: number, options?: {
    类别?: 气运类别;
    稀有度?: 气运稀有度;
    excludeNsfw?: boolean;
    nsfwOnly?: boolean;
    成人内容开启?: boolean;
    能力类型?: 气运能力类型;
    适用境界Min?: number;
    适用境界Max?: number;
}): 气运数据[] {
    let pool = applyQiyunFilters([...气运数据列表], options);
    const shuffled = pool.sort(() => Math.random() - 0.5);
    return shuffled.slice(0, Math.min(count, shuffled.length));
}

export function filterQiyun(options?: {
    类别?: 气运类别;
    稀有度?: 气运稀有度;
    excludeNsfw?: boolean;
    nsfwOnly?: boolean;
    成人内容开启?: boolean;
    能力类型?: 气运能力类型;
    适用境界Min?: number;
    适用境界Max?: number;
}): 气运数据[] {
    return applyQiyunFilters([...气运数据列表], options);
}

export function 计算气运属性修正(
    当前属性: number,
    气运列表: 气运数据[]
): number {
    let 修正因子 = 1;
    for (const qiyun of 气运列表) {
        for (const effect of qiyun.效果) {
            if (effect.类型 === '属性修正' && effect.修正值) {
                修正因子 *= effect.修正值;
            }
        }
    }
    return Math.round(当前属性 * 修正因子);
}

export function 获取气运效果描述(气运列表: 气运数据[]): string[] {
    return 气运列表.flatMap(q =>
        q.效果
            .filter(e => e.类型 === '描述效果')
            .map(e => e.描述 || '')
            .filter(Boolean)
    );
}

export function 获取气运属性列表(气运列表: 气运数据[]): Array<{属性: 气运属性类型; 修正值: number}> {
    const results: Array<{属性: 气运属性类型; 修正值: number}> = [];
    for (const qiyun of 气运列表) {
        for (const effect of qiyun.效果) {
            if (effect.类型 === '属性修正' && effect.属性 && effect.修正值) {
                results.push({ 属性: effect.属性, 修正值: effect.修正值 });
            }
        }
    }
    return results;
}